import React, { useEffect, useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

function CheckoutScreen() {

  const [cart, setCart] = useState([]);
  const [placingOrder, setPlacingOrder] = useState(false);

  const navigate = useNavigate();
  const userInfo = JSON.parse(localStorage.getItem("userInfo"));

  useEffect(() => {

    if (!userInfo) {
      navigate("/");
      return;
    }

    const selected = JSON.parse(localStorage.getItem("selectedCartItems"));

    console.log("SELECTED CART:", selected); // 🔥 DEBUG

    if (!selected || selected.length === 0) {
      navigate("/cart");
      return;
    }

    setCart(selected);

  }, [navigate, userInfo]);

  // ✅ SAFE TOTAL
  const total = cart.reduce((acc, item) => {
    const price = item.product?.price || item.price || 0;
    const qty = item.quantity || 0;
    return acc + price * qty;
  }, 0);

  const placeOrder = async () => {

    if (placingOrder) return;

    try {

      setPlacingOrder(true);

      const orderData = {
        user: userInfo._id,
        items: cart.map((item) => ({
          product: item.product?._id || item.product,
          quantity: item.quantity,
          price: item.product?.price || item.price,
          cartItemId: item._id,
        })),
        totalAmount: total,
      };

      console.log("ORDER DATA:", orderData); // 🔥 DEBUG

      const res = await axios.post(
        "http://localhost:5000/api/orders",
        orderData
      );

      const order = res.data.order || res.data;

      if (!order || !order._id) {
        alert("Order failed");
        return;
      }

      localStorage.setItem("orderInfo", JSON.stringify(order));

      navigate("/payment", {
        state: { order },
      });

    } catch (error) {

      console.log("ORDER ERROR:", error.response?.data || error.message);
      alert("Failed to place order");

    } finally {
      setPlacingOrder(false);
    }
  };

  return (
    <div style={{ padding: "20px", minHeight: "100vh", background: "#f4f6f9" }}>

      <h2 style={{ textAlign: "center" }}>🧾 Order Summary</h2>

      {cart.map((item, index) => (
        <div key={index} style={{
          background: "#fff",
          margin: "10px auto",
          padding: "15px",
          maxWidth: "500px",
          borderRadius: "10px"
        }}>
          <h3>{item.product?.name || "Product"}</h3>
          <p><b>Quantity:</b> {item.quantity}</p>
          <p><b>Price:</b> ₹ {item.product?.price || item.price || 0}</p>
        </div>
      ))}

      <div style={{ textAlign: "center", marginTop: "20px" }}>
        <h3>Total Amount: ₹ {total}</h3>

        <button
          onClick={placeOrder}
          disabled={placingOrder}
          style={{
            padding: "12px 20px",
            background: placingOrder ? "gray" : "green",
            color: "white",
            border: "none",
            borderRadius: "5px"
          }}
        >
          {placingOrder ? "Placing Order..." : "Place Order"}
        </button>
      </div>

    </div>
  );
}

export default CheckoutScreen;
